#include<bits/stdc++.h>
using namespace std;
unsigned long long ans=0,j=0,p=0;;
long long h[330];
bool sum=0;
signed main()
{
	int n;
	cin>>n;
	for (int i=1;i<=n;i++)
	{
		cin>>h[i];
	}
	sort(h+1,h+n+1);
	for (int i=1;i<=n;i++)
	{
		j=n-j+sum;
		sum=!sum;
		ans+=(h[j]-p)*(h[j]-p);
		p=h[j];
	}
	cout<<ans;
	return 0;
}
